const subscribers = $input.item.json.subscribers || [];
const wb = $('Webhook').item.json.body;
const { title, description, url, projectName, listUuid, umamiName } = wb;

const themes = {
  theunnamedroads:    { bg:'#0a0a0a', header:'#111111', textColor:'#e5e5e5', cta:'#6366f1', ctaText:'#fff', cardBg:'#111827', subText:'rgba(255,255,255,0.35)', divider:'rgba(255,255,255,0.1)' },
  thehockeybrain:     { bg:'#f0f9ff', header:'#0c4a6e', textColor:'#1e3a5f', cta:'#0ea5e9', ctaText:'#fff', cardBg:'#ffffff', subText:'#94a3b8', divider:'#bae6fd' },
  theagentfabric:     { bg:'#060d1f', header:'#0b1020', textColor:'#cbd5e1', cta:'#3b82f6', ctaText:'#fff', cardBg:'#0d1526', subText:'rgba(255,255,255,0.35)', divider:'rgba(255,255,255,0.08)' },
  theatomicnetwork:   { bg:'#f8fafc', header:'#1e3a8a', textColor:'#1e293b', cta:'#2563eb', ctaText:'#fff', cardBg:'#ffffff', subText:'#94a3b8', divider:'#e2e8f0' },
  theprintroute:      { bg:'#0f172a', header:'#1e1b4b', textColor:'#cbd5e1', cta:'#4f46e5', ctaText:'#fff', cardBg:'#1e293b', subText:'rgba(255,255,255,0.35)', divider:'rgba(255,255,255,0.08)' },
  emilingemarkarlsson:{ bg:'#f9fafb', header:'#111827', textColor:'#374151', cta:'#111827', ctaText:'#fff', cardBg:'#ffffff', subText:'#9ca3af', divider:'#e5e7eb' },
  thehockeyanalytics: { bg:'#f0f9ff', header:'#0c4a6e', textColor:'#1e3a5f', cta:'#0ea5e9', ctaText:'#fff', cardBg:'#ffffff', subText:'#94a3b8', divider:'#bae6fd' },
};

const t = themes[umamiName] || themes['theunnamedroads'];
const fromName = projectName || 'The Unnamed Roads';

const batch = subscribers.map(sub => {
  const firstName = (sub.name || '').trim().split(' ')[0];
  const greeting = firstName ? 'Hi ' + firstName + ',' : 'Hi there,';
  const safeEmail = encodeURIComponent(sub.email || '');

  const html =
    '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head>' +
    '<body style="margin:0;padding:0;background-color:' + t.bg + ';font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Helvetica,Arial,sans-serif;">' +
    '<table width="100%" cellpadding="0" cellspacing="0" style="background-color:' + t.bg + ';padding:40px 20px;">' +
    '<tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;">' +
    '<tr><td style="background-color:' + t.header + ';padding:28px 40px;border-radius:12px 12px 0 0;">' +
    '<p style="margin:0;font-size:18px;font-weight:700;color:#ffffff;letter-spacing:-0.3px;">' + fromName + '</p></td></tr>' +
    '<tr><td style="background-color:' + t.cardBg + ';padding:40px;border-radius:0 0 12px 12px;">' +
    '<p style="margin:0 0 8px;font-size:11px;color:' + t.cta + ';font-weight:700;text-transform:uppercase;letter-spacing:1.5px;">New Article</p>' +
    '<p style="margin:0 0 20px;font-size:14px;color:' + t.textColor + ';">' + greeting + '</p>' +
    '<h1 style="margin:0 0 16px;font-size:22px;font-weight:700;color:' + t.textColor + ';line-height:1.35;">' + title + '</h1>' +
    (description ? '<p style="margin:0 0 32px;font-size:15px;line-height:1.65;color:' + t.textColor + ';opacity:0.8;">' + description + '</p>' : '<p style="margin:0 0 32px;"></p>') +
    '<a href="' + url + '" style="display:inline-block;background-color:' + t.cta + ';color:' + t.ctaText + ';padding:14px 28px;border-radius:8px;text-decoration:none;font-size:14px;font-weight:600;">Read article \u2192</a>' +
    '<hr style="margin:40px 0;border:none;border-top:1px solid ' + t.divider + ';">' +
    '<p style="margin:0;font-size:12px;color:' + t.subText + ';line-height:1.7;">' +
    fromName + ' is part of <a href="https://theunnamedroads.com" style="color:' + t.cta + ';text-decoration:none;">The Unnamed Roads</a>.<br>' +
    'You\'re receiving this because you subscribed to ' + fromName + '. ' +
    '<a href="https://listmonk-v8wk0kksk00wgk0g0c4wsww0.46.62.206.47.sslip.io/subscription/manage?email=' + safeEmail + '" style="color:' + t.cta + ';">Manage subscription</a>' +
    '</p></td></tr></table></td></tr></table></body></html>';

  return { from: fromName + ' <newsletter@theunnamedroads.com>', to: [sub.email], subject: title, html };
});

return [{ json: { batch, count: batch.length, projectName: fromName, url, title } }];

const wb = $('Webhook').item.json.body;
const { title, description, url, umamiName } = wb;

// Per-site emoji + hashtags
const sites = {
  theunnamedroads:    { emoji: '🌍', tags: '#travel #writing #adventure' },
  thehockeyanalytics: { emoji: '🏒', tags: '#hockey #nhl #sportsanalytics' },
  thehockeybrain:     { emoji: '🧠', tags: '#hockey #nhl #hockeydata' },
  emilingemarkarlsson:{ emoji: '🤖', tags: '#automation #n8n #selfhosted #buildinpublic' },
  theagentfabric:     { emoji: '⚙️', tags: '#ai #agents #automation' },
  theprintroute:      { emoji: '📄', tags: '#printing #design #photography' },
};
const cfg = sites[umamiName] || { emoji: '📝', tags: '' };

// Bluesky 300 char limit; URLs resolve to link cards
const tagsStr = cfg.tags ? '\n\n' + cfg.tags : '';
const base = cfg.emoji + ' ' + title;
let text = base;

if (description) {
  const room = 290 - base.length - tagsStr.length - 2 - url.length - 2;
  if (room > 40) {
    const excerpt = description.length <= room ? description : description.slice(0, room - 1) + '\u2026';
    text += '\n\n' + excerpt;
  }
}

text += tagsStr + '\n\n' + url;

// Byte offsets for clickable URL facet
const encoder = new TextEncoder();
const byteStart = encoder.encode(text.slice(0, text.lastIndexOf(url))).length;
const byteEnd = encoder.encode(text).length;

return [{ json: { record: {
  '$type': 'app.bsky.feed.post',
  text,
  createdAt: new Date().toISOString(),
  langs: ['en'],
  facets: [{ index: { byteStart, byteEnd }, features: [{ '$type': 'app.bsky.richtext.facet#link', uri: url }] }]
} } }];

